#include <stdio.h>
#include <math.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long A,B; scanf("%lld %lld", &A, &B);
        long long S = A + B;
        long long best = LLONG_MAX;
        for(long long i=1;i*i<=S;i++){
            if(S % i == 0){
                long long d1 = i;
                long long d2 = S / i;
                if(d1 != S){
                    long long diff = llabs(d1 - B);
                    if(diff < best) best = diff;
                }
                if(d2 != S && d2 != d1){
                    long long diff = llabs(d2 - B);
                    if(diff < best) best = diff;
                }
            }
        }
        printf("%lld\n", best);
    }
    return 0;
}

