#!/usr/bin/env python3
import sys, math

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        A = int(next(it)); B = int(next(it))
        S = A + B
        best = 10**18
        i = 1
        while i * i <= S:
            if S % i == 0:
                d1 = i
                d2 = S // i
                if d1 != S:
                    best = min(best, abs(d1 - B))
                if d2 != S and d2 != d1:
                    best = min(best, abs(d2 - B))
            i += 1
        out.append(str(best))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

